  7	class InteractionSampler {
  8	public:
  9	    InteractionSampler(const std::map<int, std::set<int>>& record, const std::map<int, std::set<int>>& record_item, int num_user, int num_item)
 10	        : record_(record), record_item_(record_item), num_user_(num_user), num_item_(num_item) {}
 11	
 12	    std::vector<int> negative_sample(const std::vector<int>& user_batch) {
 13	        std::vector<int> negative_samples;
 14	        std::random_device rd;
 15	        std::mt19937 gen(rd());
 16	        std::uniform_int_distribution<> dis(0, num_item_ - 1);
 17	
 18	        for (int user_id : user_batch) {
 19	            int item_id;
 20	            do {
 21	                item_id = dis(gen);
 22	            } while (record_[user_id].count(item_id) > 0);
 23	            negative_samples.push_back(item_id);
 24	        }
 25	
 26	        return negative_samples;
 27	    }
 28	
 29	    std::pair<std::vector<int>, std::vector<int>> sample(const std::vector<int>& user_batch) {
 30	        std::vector<int> item_samples;
 31	        std::vector<int> interactions;
 32	        std::random_device rd;
 33	        std::mt19937 gen(rd());
 34	        std::uniform_int_distribution<> dis(0, num_item_ - 1);
 35	
 36	        for (int user_id : user_batch) {
 37	            int item_id = dis(gen);
 38	            item_samples.push_back(item_id);
 39	            interactions.push_back(record_[user_id].count(item_id) > 0 ? 1 : 0);
 40	        }
 41	
 42	        return {item_samples, interactions};
 43	    }
 44	
 45	    std::pair<std::vector<int>, std::vector<int>> fair_sample(const std::vector<int>& user_batch, const std::vector<int>& item_batch) {
 46	        std::vector<int> user_samples;
 47	        std::vector<int> item_samples;
 48	        int len = user_batch.size();
 49	
 50	        for (int cur = 0; cur < len; cur++) {
 51	            int u1 = user_batch[cur];
 52	            int i1 = item_batch[cur];
 53	            int delta = 1;
 54	            int u2, i2;
 55	            do {
 56	                u2 = user_batch[(cur + delta) % len];
 57	                i2 = item_batch[(cur + delta) % len];
 58	                ++delta;
 59	            } while (record_[u2].count(i1) > 0 || record_[u1].count(i2) > 0);
 60	            user_samples.push_back(u2);
 61	            item_samples.push_back(i2);
 62	        }
 63	
 64	        return {user_samples, item_samples};
 65	    }
 66	
 67	    std::tuple<std::vector<int>, std::vector<int>, std::vector<int>> fair_sample_point(const std::vector<int>& user_batch, const std::vector<int>& item_batch, const std::vector<int>& label_batch) {
 68	        std::vector<int> user_samples;
 69	        std::vector<int> item_samples;
 70	        std::vector<int> label_samples;
 71	        std::random_device rd;
 72	        std::mt19937 gen(rd());
 73	        std::uniform_int_distribution<> dis(0, num_user_ - 1);
 74	        
 75	        int len = user_batch.size();
 76	        for (int cur = 0; cur < len; cur++) {
 77	            int i2 = item_batch[cur];
 78	            int u2;
 79	            if (label_batch[cur] == 1) {
 80	                do {
 81	                    u2 = dis(gen);
 82	                } while (record_[u2].count(i2) > 0);
 83	                label_samples.push_back(0);
 84	            } else {
 85	                std::set<int> s = record_item_[i2];
 86	                if (s.size() == 0) {
 87	                    continue;
 88	                }
 89	                std::uniform_int_distribution<> dis_temp(0, s.size() - 1);
 90	                auto it = s.begin();
 91	                std::advance(it, dis_temp(gen));
 92	                u2 = *it;
 93	                label_samples.push_back(1);
 94	            }
 95	            user_samples.push_back(u2);
 96	            item_samples.push_back(i2);
 97	        }
 98	
 99	        return std::make_tuple(user_samples, item_samples, label_samples);
100	    }
101	
102	private:
103	    std::map<int, std::set<int>> record_;
104	    std::map<int, std::set<int>> record_item_;
105	    int num_user_;
106	    int num_item_;
107	};
108	
109	PYBIND11_MODULE(sampler, m) {
110	    pybind11::class_<InteractionSampler>(m, "InteractionSampler")
111	        .def(pybind11::init<std::map<int, std::set<int>>, std::map<int, std::set<int>>, int, int>())
112	        .def("negative_sample", &InteractionSampler::negative_sample)
113	        .def("sample", &InteractionSampler::sample)
114	        .def("fair_sample", &InteractionSampler::fair_sample)
115	        .def("fair_sample_point", &InteractionSampler::fair_sample_point);
116	}

